/**
 * Rooms Management Page
 * List, add, delete rooms
 */

import React, { useState, useEffect } from 'react';
import { getRooms, createRoom, deleteRoom } from '../../services/admin_service';
import SearchBar from '../../components/common/SearchBar';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';

const Rooms = () => {
    const [rooms, setRooms] = useState([]);
    const [filteredRooms, setFilteredRooms] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showAddModal, setShowAddModal] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [selectedRoom, setSelectedRoom] = useState(null);
    const [formData, setFormData] = useState({
        room_number: '',
        building: '',
        floor: '',
        capacity: '',
        room_type: 'Classroom'
    });
    const [error, setError] = useState('');

    const roomTypes = ['Classroom', 'Lecture Hall', 'Lab', 'Computer Lab', 'Seminar Room', 'Auditorium'];

    useEffect(() => {
        fetchRooms();
    }, []);

    useEffect(() => {
        filterRooms();
    }, [searchTerm, rooms]);

    const fetchRooms = async () => {
        setLoading(true);
        const result = await getRooms();
        if (result.success) {
            setRooms(result.data || []);
        } else {
            setError(result.message);
        }
        setLoading(false);
    };

    const filterRooms = () => {
        if (!searchTerm) {
            setFilteredRooms(rooms);
        } else {
            const filtered = rooms.filter(room =>
                room.room_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                room.building?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                room.room_type?.toLowerCase().includes(searchTerm.toLowerCase())
            );
            setFilteredRooms(filtered);
        }
    };

    const handleAddRoom = async () => {
        if (!formData.room_number || !formData.building || !formData.capacity) {
            setError('Room number, building, and capacity are required');
            return;
        }

        const result = await createRoom({
            ...formData,
            floor: parseInt(formData.floor) || 0,
            capacity: parseInt(formData.capacity)
        });

        if (result.success) {
            setShowAddModal(false);
            setFormData({
                room_number: '',
                building: '',
                floor: '',
                capacity: '',
                room_type: 'Classroom'
            });
            fetchRooms();
        } else {
            setError(result.message);
        }
    };

    const handleDeleteRoom = async () => {
        if (!selectedRoom) return;

        const result = await deleteRoom(selectedRoom.room_id);
        if (result.success) {
            setShowDeleteModal(false);
            setSelectedRoom(null);
            fetchRooms();
        } else {
            setError(result.message);
        }
    };

    // Helper function to get random status for demo (in real app, status comes from backend)
    const getRandomStatus = () => {
        const statuses = ['Available', 'Occupied', 'Maintenance'];
        return statuses[Math.floor(Math.random() * statuses.length)];
    };

    if (loading) return <LoadingSpinner />;

    return (
        <div className="page-container">
            <div className="page-header">
                <h1>Rooms</h1>
                <p>{rooms.length} rooms total</p>
            </div>

            <div className="page-actions">
                <SearchBar
                    placeholder="Search rooms by number, building, or type..."
                    onSearch={setSearchTerm}
                />
                <button className="btn-primary" onClick={() => setShowAddModal(true)}>
                    + Add Room
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="data-table-container">
                <table className="data-table">
                    <thead>
                        <tr>
                            <th>Room Number</th>
                            <th>Building</th>
                            <th>Floor</th>
                            <th>Capacity</th>
                            <th>Type</th>
                            <th>Status</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredRooms.map((room) => (
                            <tr key={room.room_id}>
                                <td><strong>{room.room_number}</strong></td>
                                <td>{room.building}</td>
                                <td>{room.floor || 'Ground'}</td>
                                <td>{room.capacity} seats</td>
                                <td>{room.room_type}</td>
                                <td><StatusBadge status={getRandomStatus()} /></td>
                                <td>
                                    <button
                                        className="btn-icon btn-danger"
                                        onClick={() => {
                                            setSelectedRoom(room);
                                            setShowDeleteModal(true);
                                        }}
                                    >
                                        🗑️
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {filteredRooms.length === 0 && (
                    <div className="empty-state">No rooms found</div>
                )}
            </div>

            {/* Add Room Modal */}
            <ConfirmModal
                isOpen={showAddModal}
                onClose={() => setShowAddModal(false)}
                onConfirm={handleAddRoom}
                title="Add New Room"
                message={
                    <div className="modal-form">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Room Number:</label>
                                <input
                                    type="text"
                                    value={formData.room_number}
                                    onChange={(e) => setFormData({ ...formData, room_number: e.target.value })}
                                    placeholder="A-101"
                                />
                            </div>
                            <div className="form-group">
                                <label>Building:</label>
                                <input
                                    type="text"
                                    value={formData.building}
                                    onChange={(e) => setFormData({ ...formData, building: e.target.value })}
                                    placeholder="Academic Block A"
                                />
                            </div>
                        </div>
                        <div className="form-row">
                            <div className="form-group">
                                <label>Floor:</label>
                                <input
                                    type="number"
                                    value={formData.floor}
                                    onChange={(e) => setFormData({ ...formData, floor: e.target.value })}
                                    placeholder="1"
                                />
                            </div>
                            <div className="form-group">
                                <label>Capacity:</label>
                                <input
                                    type="number"
                                    value={formData.capacity}
                                    onChange={(e) => setFormData({ ...formData, capacity: e.target.value })}
                                    placeholder="50"
                                />
                            </div>
                        </div>
                        <div className="form-group">
                            <label>Room Type:</label>
                            <select
                                value={formData.room_type}
                                onChange={(e) => setFormData({ ...formData, room_type: e.target.value })}
                            >
                                {roomTypes.map(type => (
                                    <option key={type} value={type}>{type}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                }
                confirmText="Add Room"
                confirmVariant="primary"
            />

            {/* Delete Modal */}
            <ConfirmModal
                isOpen={showDeleteModal}
                onClose={() => setShowDeleteModal(false)}
                onConfirm={handleDeleteRoom}
                title="Delete Room"
                message={`Are you sure you want to delete room "${selectedRoom?.room_number}"? This action cannot be undone.`}
                confirmText="Delete"
                confirmVariant="danger"
            />
        </div>
    );
};

export default Rooms;
